import streamlit as st
import seaborn as sns
import pandas as pd
import matplotlib.pyplot as plt

# Téléchargement des DF
flights = sns.load_dataset("flights")
taxis = sns.load_dataset("taxis")
planets = sns.load_dataset("planets")

# Création d'un dictionnaire avec nom des DF et DF
dict_df = {"flights":flights, "taxis":taxis, "planets":planets}

# Ajout du titre de la page
st.title("Manipulation de données et création de graphiques")

# Ajout du 1er sélecteur (choix dataset) que l'on met dans une variable pour réutiliser le choix de l'utilisateur ensuite
df_titres = st.selectbox("Quel dataset souhaites-tu utiliser ?", dict_df.keys())
df = dict_df[df_titres]

# Affichage du DF
st.dataframe(df)

# Ajout du 2e sélecteur (choix x) que l'on met dans une variable pour réutiliser le choix de l'utilisateur ensuite
X = st.selectbox("Choisissez la colonne X", df.columns.tolist())

# Ajout du 3e sélecteur (choix y) que l'on met dans une variable pour réutiliser le choix de l'utilisateur ensuite
Y = st.selectbox("Choisissez la colonne Y", df.columns.tolist())

# Ajout du 4e sélecteur (choix graphique) que l'on met dans une variable pour réutiliser le choix de l'utilisateur ensuite
liste_graphiques = ["scatter_chart","bar_chart","line_chart"] # Création liste graphiques
type_graphique = st.selectbox("Quel graphique veux-tu utiliser ?", liste_graphiques)

# Affichage graphique
if type_graphique == "scatter_chart" :
  st.scatter_chart(data = df, x=X, y=Y)
elif type_graphique == "bar_chart" :
  st.bar_chart(data = df, x=X, y=Y)
elif type_graphique == "line_chart" :
  st.line_chart(data = df, x=X, y=Y)

# Ajout du 5e sélecteur (case à cocher)
affichage_matrice = st.checkbox(label="Afficher la matrice de corrélation")

# Affichage matrice corrélation
if affichage_matrice == True :
  st.header("Ma matrice de corrélation")
  correlation = df.corr(numeric_only=True)
  fig, ax = plt.subplots()
  sns.heatmap(correlation, annot=True)
  st.pyplot(fig)
